import React, { useState } from "react";
import "./styles.css";
import { BrowserRouter, Routes, Route } from "react-router-dom";
import Layout from "./components/Layout";
import ChatboxButton from "./components/ChatboxButton";
import Dashboard from "./pages/Dashboard";
import ProgramAvatar from "./pages/ProgramAvatar";
import Challenges from "./pages/Challenges";
import GoalsProgress from "./pages/GoalsProgress";
import ActivityFoodLog from "./pages/ActivityFoodLog";
import Notifications from "./pages/Notifications";
import Chatbot from "./pages/Chatbot";

const DEFAULT_SELECTIONS = {
  skin: 's1', hairStyle: 'hs1', hairColor: 'hc1',
  animalEars: 'ae1', armour: 'ar1', pets: null,
};

const loadSelections = () => {
  try { const s = localStorage.getItem('healup_avatar_selections'); return s ? JSON.parse(s) : DEFAULT_SELECTIONS; }
  catch { return DEFAULT_SELECTIONS; }
};
const loadAvatarName = () => {
  try { return localStorage.getItem('healup_avatar_name') || ''; } catch { return ''; }
};
const loadStats = () => {
  try { const s = localStorage.getItem('healup_stats'); return s ? JSON.parse(s) : { xp: 0, coins: 0 }; }
  catch { return { xp: 0, coins: 0 }; }
};
const loadBars = () => {
  try { const s = localStorage.getItem('healup_bars'); return s ? JSON.parse(s) : { hp: 65, energy: 80, discipline: 45 }; }
  catch { return { hp: 65, energy: 80, discipline: 45 }; }
};

function App() {
  const [avatarSelections, setAvatarSelections] = useState(loadSelections);
  const [avatarName, setAvatarName]             = useState(loadAvatarName);
  const [stats, setStats]                       = useState(loadStats);
  const [bars, setBars]                         = useState(loadBars);

  const handleSetSelections = (updater) => {
    setAvatarSelections(prev => {
      const next = typeof updater === 'function' ? updater(prev) : updater;
      localStorage.setItem('healup_avatar_selections', JSON.stringify(next));
      return next;
    });
  };

  const handleSetAvatarName = (name) => {
    setAvatarName(name);
    localStorage.setItem('healup_avatar_name', name);
  };

  // Called from Challenges on checkbox tick
  const handleChallengeComplete = (xpGain, coinGain, barEffects) => {
    // Update XP + coins
    setStats(prev => {
      const next = { xp: prev.xp + xpGain, coins: prev.coins + coinGain };
      localStorage.setItem('healup_stats', JSON.stringify(next));
      return next;
    });
    // Update HP / Energy / Discipline bars (capped at 100)
    if (barEffects) {
      setBars(prev => {
        const next = {
          hp:         Math.min(100, prev.hp         + (barEffects.hp         || 0)),
          energy:     Math.min(100, prev.energy     + (barEffects.energy     || 0)),
          discipline: Math.min(100, prev.discipline + (barEffects.discipline || 0)),
        };
        localStorage.setItem('healup_bars', JSON.stringify(next));
        return next;
      });
    }
  };

  return (
    <BrowserRouter>
      <Layout stats={stats}>
        <Routes>
          <Route path="/" element={
            <Dashboard avatarSelections={avatarSelections} avatarName={avatarName} bars={bars} />
          } />
          <Route path="/program" element={
            <ProgramAvatar
              avatarSelections={avatarSelections}
              setAvatarSelections={handleSetSelections}
              avatarName={avatarName}
              setAvatarName={handleSetAvatarName}
            />
          } />
          <Route path="/challenges" element={
            <Challenges onChallengeComplete={handleChallengeComplete} bars={bars} />
          } />
          <Route path="/goals"         element={<GoalsProgress />} />
          <Route path="/activity-food" element={<ActivityFoodLog />} />
          <Route path="/notifications" element={<Notifications />} />
          <Route path="/chatbot"       element={<Chatbot />} />
        </Routes>
        <ChatboxButton />
      </Layout>
    </BrowserRouter>
  );
}

export default App;
